/// <summary>
/// This class is an extension of SalesLine Table
/// </summary>
[ExtensionOf(tablestr(SalesLine))]
final class ETGSalesLine_Extension
{







}

Method.Source:
/// <summary>
/// Calculating the Depositamount field when DepositRate and SalesQty fields are modified
/// </summary>
/// <param name = "_fieldId">FieldId</param>
public void modifiedField(FieldId _fieldId)
{
    next modifiedField(_fieldId);

    switch (_fieldId)
    {
        case fieldNum(SalesLine, ETGDepositRate):
            if(SalesParameters::find().ETGEnableCylinderTracking)
            {
                if(this.ETGDepositRate < 0)
                {
                    this.ETGDepositRate = 0;
                    throw error(strFmt("@ETG_New:DepositRateValue", this.ItemId));
                }
                this.ETGDepositAmount = this.ETGDepositRate * this.SalesQty;
            }
            break;

        case fieldNum(SalesLine, SalesQty):
            if(SalesParameters::find().ETGEnableCylinderTracking)
            {
                this.ETGDepositAmount = this.ETGDepositRate * this.SalesQty;
            }
            break;

    }

}

/// <summary>
/// Validating SalesQty, ConnectinType fields
/// </summary>
/// <param name = "_fieldId">FieldId</param>
/// <returns>Boolean</returns>
public boolean  validateField(FieldId  _fieldId)
{
    boolean ok = true;

    ok = next validateField(_fieldId);

    if(ok)
    {
        switch(_fieldId)
        {
            case fieldNum(SalesLine, SalesQty):
            case fieldNum(SalesLine, ETGConnectionType):
                if(SalesParameters::find().ETGEnableCylinderTracking == NoYes::Yes)
                {
                    ok = this.etgValidateDepositAmt();
                }
                break;
            //case fieldNum(SalesLine, ETGRefSalesId):
            //    if(ETGACFParameters::find().EnableManageMultiCurrencyFeature == NoYes::Yes 
            //        && this.ETGRefSalesId == this.SalesId)
            //    {
            //        ok = checkFailed(strFmt("Sales order %1 can not be selected", this.SalesId));
            //    }
            //    break;
        }
    }

    return ok;
}

/// <summary>
/// Contains the logic for validating deposit amount field
/// </summary>
/// <returns>Boolean</returns>
public boolean etgValidateDepositAmt()
{
    boolean isValid = true;
    SalesTable        salesTable        = this.salesTable();
    InventTableModule inventTableModule = InventTableModule::find(this.ItemId, ModuleInventPurchSales::Sales);

    if(this.ETGConnectionType == ETGConnectionType::Surrenderofcylinders
        && inventTableModule.ETGDepositNeeded == NoYes::Yes
        && this.SalesQty >= 0)
    {
        isValid = checkFailed(strFmt("@ETG_New:QtyValidation", this.ItemId));
    }

    return isValid;
}

    /// <summary>
    /// Validates the record before saving. We re-apply the agreement price
    /// here to safely catch and revert any automated price changes from Batch/Serial updates.
    /// </summary>
    public boolean validateWrite(boolean _checkCues)
